class TestHookRelayMarker:
    """Verify --marker path skips stdin and writes a marker line."""

    def test_marker_with_text_returns_without_reading_stdin(self):
        # If stdin were read, this StringIO would be consumed; assert it isn't.
        stdin = io.StringIO("would-be-payload")
        with patch("sys.stdin", stdin):
            rc = main(["--marker", "boundary", "after", "fix"])
        assert rc == EXIT_SUCCESS
        assert stdin.read() == "would-be-payload"  # untouched

    def test_marker_without_value_still_returns_success(self):
        with patch("sys.stdin", io.StringIO("")):
            rc = main(["--marker"])
        assert rc == EXIT_SUCCESS


class TestHookRelayStdinPath:
    """Verify the POST path is taken when stdin has a payload."""

    def test_payload_is_posted_to_dashboard(self):
        payload = json.dumps({"event": "Stop", "session_id": "abc"})
        with (
            patch("sys.stdin", io.StringIO(payload)),
            patch("urllib.request.urlopen") as mock_urlopen,
        ):
            rc = main([])
        assert rc == EXIT_SUCCESS
        assert mock_urlopen.called
        req = mock_urlopen.call_args.args[0]
        assert req.full_url == "http://127.0.0.1:17384/hook"
        assert req.data == payload.encode()

    def test_network_failure_is_swallowed(self):
        payload = json.dumps({"event": "Stop"})
        with (
            patch("sys.stdin", io.StringIO(payload)),
            patch("urllib.request.urlopen", side_effect=ConnectionRefusedError()),
        ):
            rc = main([])
        assert rc == EXIT_SUCCESS  # silent failure, never crashes

    def test_malformed_json_does_not_crash_in_debug(self):
        with patch("sys.stdin", io.StringIO("not-json")), patch("urllib.request.urlopen"):
            rc = main(["--debug"])
        assert rc == EXIT_SUCCESS
